#include <bits/stdc++.h>
using namespace std;
char a;
int b,c,d;
stack<int> z;
int main() {
	cin>>a;
	while(a!='@'){
		int s=0;
		if(a>='0'&&a<='9'){
			while(a>='0'&&a<='9'){
				s=s*10+int(a-'0');
				cin>>a;
			}
		}
		if(a=='.')z.push(s);
		else if(a=='+' || a=='-' || a=='*' || a=='/'){
			d=z.top();
			z.pop();
			c=z.top();
			z.pop();
			if(a=='+'){
				z.push(c+d);
			}
			if(a=='-'){
				z.push(c-d);
			}
			if(a=='*'){
				z.push(c*d);
			}
			if(a=='/'){
				z.push(c/d);
			}
		}
		cin>>a;
	}
	cout<<z.top();
	return 0;
}
